option.value:
import React, { useState } from 'react';
import { MessageSquare, ShieldCheck, Terminal } from 'lucide-react';

export default function CopilotInterface() {
    const [input, setInput] = useState("");

    return (
        <div className="flex h-screen bg-[#0d1117] text-white font-sans">
            {/* Sidebar */}
            <div className="w-16 flex flex-col items-center py-4 border-r border-gray-700 space-y-4">
                <MessageSquare className="text-blue-400 cursor-pointer" />
                <Terminal className="text-gray-400 hover:text-white cursor-pointer" />
            </div>

            {/* Main Chat Area */}
            <div className="flex-1 flex flex-col">
                <header className="p-4 border-b border-gray-700 flex justify-between">
                    <span className="font-semibold text-sm text-gray-300">GitHub Copilot MCP Hub</span>
                    <ShieldCheck size={18} className="text-green-500" />
                </header>

                <main className="flex-1 overflow-y-auto p-6 space-y-4">
                    <div className="bg-[#161b22] p-4 rounded-lg max-w-2xl border border-gray-700">
                        How can I help you interact with your Jira MCP server today?
                    </div>
                </main>

                {/* Input Bar */}
                <footer className="p-4 bg-[#0d1117]">
                    <div className="max-w-3xl mx-auto relative">
            <textarea
                className="w-full bg-[#161b22] border border-gray-700 rounded-xl p-4 pr-12 focus:outline-none focus:ring-1 focus:ring-blue-500"
                placeholder="Ask MCP to fetch Jira tickets..."
                rows={2}
                value={input}
                onChange={(e) => setInput(e.target.value)}
            />
                    </div>
                </footer>
            </div>
        </div>
    );
}

:root {
  --text: #6b6375;
  --text-h: #08060d;
  --bg: #fff;
  --border: #e5e4e7;
  --code-bg: #f4f3ec;
  --accent: #aa3bff;
  --accent-bg: rgba(170, 59, 255, 0.1);
  --accent-border: rgba(170, 59, 255, 0.5);
  --social-bg: rgba(244, 243, 236, 0.5);
  --shadow:
    rgba(0, 0, 0, 0.1) 0 10px 15px -3px, rgba(0, 0, 0, 0.05) 0 4px 6px -2px;

  --sans: system-ui, 'Segoe UI', Roboto, sans-serif;
  --heading: system-ui, 'Segoe UI', Roboto, sans-serif;
  --mono: ui-monospace, Consolas, monospace;

  font: 18px/145% var(--sans);
  letter-spacing: 0.18px;
  color-scheme: light dark;
  color: var(--text);
  background: var(--bg);
  font-synthesis: none;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;

  @media (max-width: 1024px) {
    font-size: 16px;
  }
}

@media (prefers-color-scheme: dark) {
  :root {
    --text: #9ca3af;
    --text-h: #f3f4f6;
    --bg: #16171d;
    --border: #2e303a;
    --code-bg: #1f2028;
    --accent: #c084fc;
    --accent-bg: rgba(192, 132, 252, 0.15);
    --accent-border: rgba(192, 132, 252, 0.5);
    --social-bg: rgba(47, 48, 58, 0.5);
    --shadow:
      rgba(0, 0, 0, 0.4) 0 10px 15px -3px, rgba(0, 0, 0, 0.25) 0 4px 6px -2px;
  }

  #social .button-icon {
    filter: invert(1) brightness(2);
  }
}

body {
  margin: 0;
}

#root {
  width: 1126px;
  max-width: 100%;
  margin: 0 auto;
  text-align: center;
  border-inline: 1px solid var(--border);
  min-height: 100svh;
  display: flex;
  flex-direction: column;
  box-sizing: border-box;
}

h1,
h2 {
  font-family: var(--heading);
  font-weight: 500;
  color: var(--text-h);
}

h1 {
  font-size: 56px;
  letter-spacing: -1.68px;
  margin: 32px 0;
  @media (max-width: 1024px) {
    font-size: 36px;
    margin: 20px 0;
  }
}
h2 {
  font-size: 24px;
  line-height: 118%;
  letter-spacing: -0.24px;
  margin: 0 0 8px;
  @media (max-width: 1024px) {
    font-size: 20px;
  }
}
p {
  margin: 0;
}

code,
.counter {
  font-family: var(--mono);
  display: inline-flex;
  border-radius: 4px;
  color: var(--text-h);
}

code {
  font-size: 15px;
  line-height: 135%;
  padding: 4px 8px;
  background: var(--code-bg);
}

